#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main() {
    char line[5000];
    int T;
    if (!fgets(line, sizeof(line), stdin)) return 0;
    sscanf(line, "%d", &T);
    while (T--) {
        int n;
        fgets(line, sizeof(line), stdin);
        sscanf(line, "%d", &n);
        int *arr = (int *)malloc(n * sizeof(int));
        int *nge = (int *)malloc(n * sizeof(int));
        int *stack = (int *)malloc(n * sizeof(int));
        int top = -1;
        fgets(line, sizeof(line), stdin);
        char *ptr = line;
        for (int i = 0; i < n; ++i) {
            while (*ptr == ' ') ++ptr;
            sscanf(ptr, "%d", &arr[i]);
            while (*ptr && *ptr != ' ' && *ptr != '\n') ++ptr;
        }
        for (int i = n - 1; i >= 0; --i) {
            while (top != -1 && stack[top] <= arr[i]) --top;
            nge[i] = (top == -1) ? -1 : stack[top];
            stack[++top] = arr[i];
        }
        for (int i = 0; i < n; ++i) {
            printf("%d%s", nge[i], i == n - 1 ? "\n" : " ");
        }
        free(arr);
        free(nge);
        free(stack);
    }
    return 0;
}

