#include <bits/stdc++.h>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T;
    if(!(cin >> T)) return 0;
    while (T--) {
        int n; cin >> n;
        vector<int> arr(n), nge(n);
        for (int i = 0; i < n; ++i) cin >> arr[i];
        stack<int> st; // monotonic decreasing stack of values
        for (int i = n - 1; i >= 0; --i) {
            while (!st.empty() && st.top() <= arr[i]) st.pop();
            nge[i] = st.empty() ? -1 : st.top();
            st.push(arr[i]);
        }
        for (int i = 0; i < n; ++i) {
            cout << nge[i] << (i == n - 1 ? '\n' : ' ');
        }
    }
    return 0;
}

